#!/usr/bin/env python3# -*- coding: utf-8 -*-import jsonimport osimport loggingimport mathimport refrom typing import Dict, List, Optional, Tupletry:    import pyproj    PYPROJ_AVAILABLE = Trueexcept ImportError:    PYPROJ_AVAILABLE = Falselogger = logging.getLogger(__name__)CACHE_FILE = "data/zone_params_cache.json"class ZoneParamsCollector:    """    Класс для точного пересчета координат Гаусса‑Крюгера (СК‑42) в географические.    Использует либо библиотеку pyproj (рекомендуется), либо встроенные точные формулы.    """    # Параметры эллипсоида Красовского (СК-42)    KRASOVSKY_A = 6378245.0          # большая полуось (м)    KRASOVSKY_ALPHA = 1 / 298.3      # сжатие    KRASOVSKY_E2 = 2 * KRASOVSKY_ALPHA - KRASOVSKY_ALPHA ** 2  # квадрат эксцентриситета    ZONES_BASE = {        '4': {'epsg': 28404, 'name': 'Зона 4 (СК-42)', 'central_meridian': 21, 'zone_number': 4,              'offset_x': 6100000, 'offset_y': 5300000, 'dx': 805, 'dy': 45},        '5': {'epsg': 28405, 'name': 'Зона 5 (СК-42)', 'central_meridian': 27, 'zone_number': 5,              'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83},        '6': {'epsg': 28406, 'name': 'Зона 6 (СК-42)', 'central_meridian': 33, 'zone_number': 6,              'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34},        '7': {'epsg': 28407, 'name': 'Зона 7 (СК-42)', 'central_meridian': 39, 'zone_number': 7,              'offset_x': 6210000, 'offset_y': 6650000, 'dx': 801, 'dy': -13},        '8': {'epsg': 28408, 'name': 'Зона 8 (СК-42)', 'central_meridian': 45, 'zone_number': 8,              'offset_x': 6220000, 'offset_y': 6800000, 'dx': 800, 'dy': -25},        '9': {'epsg': 28409, 'name': 'Зона 9 (СК-42)', 'central_meridian': 51, 'zone_number': 9,              'offset_x': 6230000, 'offset_y': 6950000, 'dx': 799, 'dy': -35}    }    MAP_SHEETS = {        # Тверская область (зона 6)        'O-36-141': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-142': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-143': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-144': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'O-36-145': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-17': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-18': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-19': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-20': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        'N-36-21': {'zone': '6', 'offset_x': 6200000, 'offset_y': 6500000, 'dx': 802, 'dy': 34, 'region': 'tver'},        # Смоленская область (зона 5)        'N-35-9': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-10': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'N-35-11': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-21': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-22': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-23': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-24': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-25': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-26': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-27': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'},        'O-35-28': {'zone': '5', 'offset_x': 6200000, 'offset_y': 5500000, 'dx': 807, 'dy': 83, 'region': 'smolensk'}    }    REGION_BOUNDARIES = {        'tver': {'name': 'Тверская область', 'lat_min': 55.5, 'lat_max': 58.5, 'lon_min': 30.0, 'lon_max': 38.0},        'smolensk': {'name': 'Смоленская область', 'lat_min': 53.5, 'lat_max': 56.0, 'lon_min': 30.0, 'lon_max': 35.0},        'moscow': {'name': 'Московская область', 'lat_min': 54.5, 'lat_max': 57.0, 'lon_min': 35.0, 'lon_max': 40.0}    }    def __init__(self):        self.cache = self._load_cache()        self._init_proj_transformers()        logger.info("ZoneParamsCollector инициализирован")    def _init_proj_transformers(self):        """Инициализирует трансформеры pyproj для всех зон (если библиотека доступна)"""        self.transformers = {}        if PYPROJ_AVAILABLE:            try:                for zone_num, zone_params in self.ZONES_BASE.items():                    epsg = zone_params['epsg']                    src_crs = pyproj.CRS(f"EPSG:{epsg}")                    dst_crs = pyproj.CRS("EPSG:4326")                    transformer = pyproj.Transformer.from_crs(src_crs, dst_crs, always_xy=True)                    self.transformers[zone_num] = transformer                    logger.info(f"✅ Трансформер для зоны {zone_num} (EPSG:{epsg}) готов")            except Exception as e:                logger.error(f"Ошибка инициализации pyproj: {e}")        else:            logger.warning("⚠️ pyproj не установлен, используются упрощенные формулы")    def _load_cache(self) -> Dict:        if os.path.exists(CACHE_FILE):            try:                with open(CACHE_FILE, 'r', encoding='utf-8') as f:                    return json.load(f)            except Exception:                return {}        return {}    def _save_cache(self):        os.makedirs(os.path.dirname(CACHE_FILE), exist_ok=True)        try:            with open(CACHE_FILE, 'w', encoding='utf-8') as f:                json.dump(self.cache, f, ensure_ascii=False, indent=2)            logger.info(f"Кэш сохранен: {CACHE_FILE}")        except Exception:            pass    def get_zone_params(self, zone_number: str) -> Optional[Dict]:        return self.ZONES_BASE.get(zone_number)    def get_sheet_params(self, sheet_name: str) -> Optional[Dict]:        return self.MAP_SHEETS.get(sheet_name.upper())    def is_zonal_coordinate(self, x: float, y: float) -> bool:        """Определяет, являются ли координаты уже зональными (СК-42)"""        return x > 5000000 and y > 5000000    def is_short_coordinate(self, x: float, y: float) -> bool:        """Проверяет, являются ли координаты короткими (последние 5 цифр)"""        return x < 100000 and y < 100000    def detect_zone_from_zonal_y(self, y: float) -> Optional[str]:        """Определяет зону по первой цифре Y (в зональных координатах)"""        y_int = int(y)        y_str = str(y_int)        if len(y_str) >= 7:            zone_digit = y_str[0]            if zone_digit in self.ZONES_BASE:                logger.info(f"Определена зона по Y: {zone_digit} (Y={y})")                return zone_digit        return None    def gauss_kruger_to_geographic(self, x: float, y: float, zone_number: int) -> Tuple[float, float]:        """        Точный пересчет прямоугольных координат Гаусса‑Крюгера в географические.        Использует формулы, основанные на ГОСТ 51794-2001 и справочных данных.        """        logger.info(f"=== ПЕРЕСЧЕТ (упрощенные формулы) ===")        logger.info(f"X={x}, Y={y}, зона={zone_number}")        a = self.KRASOVSKY_A        e2 = self.KRASOVSKY_E2        n = zone_number        lon0 = n * 6 - 3        # Критически важно: вычитаем номер зоны и фиктивное смещение 500000 м        y_local = y - n * 1000000 - 500000        logger.info(f"y_local = {y} - {n}*1e6 - 500000 = {y_local}")        logger.info(f"Осевой меридиан: {lon0}°")        # Начальное приближение широты        B0 = x / 111000.0        B = math.radians(B0)        for _ in range(6):            sinB = math.sin(B)            cosB = math.cos(B)            N = a / math.sqrt(1 - e2 * sinB * sinB)            M = a * (1 - e2) / (1 - e2 * sinB * sinB) ** 1.5            t = math.tan(B)            eta2 = e2 / (1 - e2) * cosB * cosB            y2 = y_local * y_local            y3 = y2 * y_local            y4 = y3 * y_local            B_new = B - (N * t) / M * (                y2 / (2 * N * N) -                y4 / (24 * N * N * N * N) * (5 + 3 * t * t + eta2 - 9 * eta2 * t * t)            )            B = B_new        sinB = math.sin(B)        cosB = math.cos(B)        N = a / math.sqrt(1 - e2 * sinB * sinB)        t = math.tan(B)        y1 = y_local / N        y3 = y1 ** 3        y5 = y1 ** 5        lon = lon0 + (            y1 / cosB -            y3 / (6 * cosB) * (1 + 2 * t * t) +            y5 / (120 * cosB) * (5 + 28 * t * t + 24 * t ** 4)        ) * 180 / math.pi        lat = B * 180 / math.pi        logger.info(f"Результат: lat={lat:.6f}, lon={lon:.6f}")        return lat, lon    def gauss_kruger_to_geographic_pyproj(self, x: float, y: float, zone_number: str) -> Tuple[float, float]:        """Пересчет с помощью библиотеки pyproj (наивысшая точность)"""        if not PYPROJ_AVAILABLE:            return self.gauss_kruger_to_geographic(x, y, int(zone_number))        transformer = self.transformers.get(zone_number)        if not transformer:            logger.warning(f"Трансформер для зоны {zone_number} не найден")            return self.gauss_kruger_to_geographic(x, y, int(zone_number))        try:            logger.info(f"Используем pyproj для зоны {zone_number}")            lon, lat = transformer.transform(y, x)   # pyproj ожидает (x,y) = (восток, север)            logger.info(f"pyproj результат: lat={lat:.6f}, lon={lon:.6f}")            return lat, lon        except Exception as e:            logger.error(f"Ошибка pyproj: {e}")            return self.gauss_kruger_to_geographic(x, y, int(zone_number))    def detect_region(self, lat: float, lon: float) -> str:        for key, bounds in self.REGION_BOUNDARIES.items():            if bounds['lat_min'] <= lat <= bounds['lat_max'] and bounds['lon_min'] <= lon <= bounds['lon_max']:                logger.info(f"Точка попадает в {bounds['name']}")                return key        return 'unknown'    def decimal_to_dms(self, deg: float, direction: str) -> str:        if deg < 0:            deg = -deg            direction = 'Ю' if direction == 'С' else 'З'        d = int(deg)        m_float = (deg - d) * 60        m = int(m_float)        s = (m_float - m) * 60        return f"{d}°{m:02d}'{s:.1f}\" {direction}"    def calculate_coordinates(self, x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:        """Основной метод – определяет тип ввода и вызывает соответствующий пересчет"""        logger.info(f"=== НАЧАЛО РАСЧЕТА ===")        logger.info(f"Вход: x={x}, y={y}, zone={zone_number}, sheet={sheet_name}")        result = {            'x_input': x, 'y_input': y, 'zone_number': zone_number, 'sheet': sheet_name,            'input_type': 'unknown', 'success': False, 'errors': [], 'region': 'unknown'        }        is_zonal = self.is_zonal_coordinate(x, y)        is_short = self.is_short_coordinate(x, y)        if is_zonal:            result['input_type'] = 'zonal_sk42'            if not zone_number:                zone_number = self.detect_zone_from_zonal_y(y)                if zone_number:                    result['zone_number'] = zone_number            if not zone_number:                result['errors'].append("Не удалось определить зону")                return result            zone_num = int(zone_number)            if PYPROJ_AVAILABLE:                lat, lon = self.gauss_kruger_to_geographic_pyproj(x, y, zone_number)            else:                lat, lon = self.gauss_kruger_to_geographic(x, y, zone_num)            result['x_sk42'] = x            result['y_sk42'] = y            result['latitude'] = lat            result['longitude'] = lon            result['zone'] = f"Зона {zone_number} (СК-42)"            result['epsg'] = self.ZONES_BASE.get(zone_number, {}).get('epsg', 28406)            result['central_meridian'] = zone_num * 6 - 3        elif is_short and sheet_name:            result['input_type'] = 'short_with_sheet'            sheet = self.get_sheet_params(sheet_name)            if not sheet:                result['errors'].append(f"Лист карты {sheet_name} не найден")                return result            zone_number = sheet['zone']            result['zone_number'] = zone_number            x_full = sheet['offset_x'] + x            y_full = sheet['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full            x_sk42 = x_full + sheet.get('dx', 0)            y_sk42 = y_full + sheet.get('dy', 0)            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            zone_num = int(zone_number)            if PYPROJ_AVAILABLE:                lat, lon = self.gauss_kruger_to_geographic_pyproj(x_sk42, y_sk42, zone_number)            else:                lat, lon = self.gauss_kruger_to_geographic(x_sk42, y_sk42, zone_num)            result['latitude'] = lat            result['longitude'] = lon            result['zone'] = f"Зона {zone_number} (СК-42)"            result['epsg'] = self.ZONES_BASE.get(zone_number, {}).get('epsg', 28406)            result['central_meridian'] = zone_num * 6 - 3        else:            result['input_type'] = 'local'            if not zone_number:                zone_number = '6'            zone_params = self.get_zone_params(zone_number)            if not zone_params:                result['errors'].append(f"Зона {zone_number} не найдена")                return result            x_full = zone_params['offset_x'] + x            y_full = zone_params['offset_y'] + y            result['x_full'] = x_full            result['y_full'] = y_full            x_sk42 = x_full + zone_params['dx']            y_sk42 = y_full + zone_params['dy']            result['x_sk42'] = x_sk42            result['y_sk42'] = y_sk42            zone_num = int(zone_number)            if PYPROJ_AVAILABLE:                lat, lon = self.gauss_kruger_to_geographic_pyproj(x_sk42, y_sk42, zone_number)            else:                lat, lon = self.gauss_kruger_to_geographic(x_sk42, y_sk42, zone_num)            result['latitude'] = lat            result['longitude'] = lon            result['zone'] = zone_params['name']            result['epsg'] = zone_params['epsg']            result['central_meridian'] = zone_params['central_meridian']        result['region'] = self.detect_region(result['latitude'], result['longitude'])        result['latitude_dms'] = self.decimal_to_dms(result['latitude'], 'С')        result['longitude_dms'] = self.decimal_to_dms(result['longitude'], 'В')        result['success'] = True        logger.info(f"=== РЕЗУЛЬТАТ: {result['latitude']:.6f}, {result['longitude']:.6f} ===")        return result    def detect_zone_by_coordinates(self, x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:        if zone_hint and zone_hint in self.ZONES_BASE:            return self.ZONES_BASE[zone_hint]        if sheet_name:            sheet = self.get_sheet_params(sheet_name)            if sheet:                return self.ZONES_BASE.get(sheet['zone'])        if self.is_zonal_coordinate(x, y):            zone_num = self.detect_zone_from_zonal_y(y)            if zone_num:                return self.ZONES_BASE.get(zone_num)        return self.ZONES_BASE.get('6')    def get_all_zones(self) -> List[str]:        return list(self.ZONES_BASE.keys())    def get_all_sheets(self) -> List[str]:        return list(self.MAP_SHEETS.keys())    def get_region_info(self, region_key: str) -> Optional[Dict]:        return self.REGION_BOUNDARIES.get(region_key)    def get_all_regions(self) -> List[str]:        return list(self.REGION_BOUNDARIES.keys())# Функции для быстрого вызоваdef get_zone_params(zone_number: str) -> Optional[Dict]:    return ZoneParamsCollector().get_zone_params(zone_number)def get_sheet_params(sheet_name: str) -> Optional[Dict]:    return ZoneParamsCollector().get_sheet_params(sheet_name)def detect_zone_by_coords(x: float, y: float, zone_hint: str = None, sheet_name: str = None) -> Optional[Dict]:    return ZoneParamsCollector().detect_zone_by_coordinates(x, y, zone_hint, sheet_name)def calculate_coordinates(x: float, y: float, zone_number: str = None, sheet_name: str = None) -> Dict:    return ZoneParamsCollector().calculate_coordinates(x, y, zone_number, sheet_name)def get_all_zones() -> List[str]:    return ZoneParamsCollector().get_all_zones()def get_all_sheets() -> List[str]:    return ZoneParamsCollector().get_all_sheets()def get_region_info(region_key: str) -> Optional[Dict]:    return ZoneParamsCollector().get_region_info(region_key)def get_all_regions() -> List[str]:    return ZoneParamsCollector().get_all_regions()